    "detachment_rules": [
      {
        "id": "det-000008356",
        "name": "Hyper-adaptations",
        "phases": [
          "any"
        ],
        "timing": "Detachment Rule - Invasion Fleet",
        "type": "detachment",
        "summary": "At the start of the first battle round, select one of the following Hyper-adaptations to be active for TYRANIDS units from your army until the end of the battle:\nSwarming Instincts\nEach time a TYRANIDS model with this Hyper-adaptation makes an attack that targets an INFANTRY or SWARM unit, that attack has the [SUSTAINED HITS 1] ability.\nHyper-aggression\nEach time a TYRANIDS model with this Hyper-adaptation makes an attack that targets a MONSTER or VEHICLE unit, that attack has the [LETHAL HITS] ability.\nHive Predators\nEach time a TYRANIDS model with this Hyper-adaptation makes an attack that targets a CHARACTER unit, on a Critical Hit , that attack has the [PRECISION] ability.",
        "source": "Wahapedia CSV / Invasion Fleet",
        "priority": 5
      },
      {
        "id": "det-000008403",
        "name": "Enraged Behemoths",
        "phases": [
          "any"
        ],
        "timing": "Detachment Rule - Crusher Stampede",
        "type": "detachment",
        "summary": "Each time a Tyranids Monster model from your army makes an attack, add 1 to the Hit roll if that model’s unit is below its Starting Strength, and add 1 to the Wound roll as well if that model’s unit is Below Half-strength. In addition, while a TYRANIDS MONSTER unit from your army (excluding Battle-shocked units) is at its Starting Strength, add 2 to the Objective Control characteristic of models in that unit.",
        "source": "Wahapedia CSV / Crusher Stampede",
        "priority": 5
      },
      {
        "id": "det-000008407",
        "name": "Insurmountable Odds",
        "phases": [
          "any"
        ],
        "timing": "Detachment Rule - Unending Swarm",
        "type": "detachment",
        "summary": "Each time an enemy unit is selected to shoot, after that unit has finished making its attacks, if one or more models from one or more Endless Multitude units from your army were destroyed as a result of those attacks, each such unit can make a Surge move. To do so, roll one D6: that unit can be moved a distance in inches up to the result, but that unit must end that move as close as possible to the closest enemy unit (excluding AIRCRAFT ). When doing so, those models can be moved within Engagement Range of enemy units. A unit cannot make a Surge move while it is Battle-shocked.",
        "source": "Wahapedia CSV / Unending Swarm",
        "priority": 5
      },
      {
        "id": "det-000008411",
        "name": "Feed the Swarm",
        "phases": [
          "any"
        ],
        "timing": "Detachment Rule - Assimilation Swarm",
        "type": "detachment",
        "summary": "In your Command phase, each Harvester unit from your army can Regenerate one friendly TYRANIDS unit that is within 6\" of it. A unit can only be regenerated once per phase. Each time a unit regenerates, do one of the following:\n- One model in that unit regains up to D3+1 lost wounds.\n- One destroyed Infantry model (excluding Characters) is returned to that unit with its full wounds remaining. If that unit is an Endless Multitude unit, up to 3 destroyed models are returned instead.",
        "source": "Wahapedia CSV / Assimilation Swarm",
        "priority": 5
      },
      {
        "id": "det-000008415",
        "name": "Questing Tendrils",
        "phases": [
          "any"
        ],
        "timing": "Detachment Rule - Vanguard Onslaught",
        "type": "detachment",
        "summary": "TYRANIDS units with this ability are eligible to charge in a turn in which they Fell Back. Vanguard Invader units with this ability are eligible to charge in a turn in which they Advanced.",
        "source": "Wahapedia CSV / Vanguard Onslaught",
        "priority": 5
      },
      {
        "id": "det-000008420",
        "name": "Synaptic Imperatives",
        "phases": [
          "any"
        ],
        "timing": "Detachment Rule - Synaptic Nexus",
        "type": "detachment",
        "summary": "At the start of the battle round, you can select one of the Synaptic Imperatives shown below. Until the end of the battle round, that Synaptic Imperative is active for your army and while a TYRANIDS unit from your army is within Synapse Range of your army, it will benefit from it. Each Synaptic Imperative can only be selected once per battle.\n- Synaptic Augmentation: While this unit is within Synapse Range of your army, models in this unit have a 5+ invulnerable save.\n- Surging Vitality: While this unit is within Synapse Range of your army, add 1 to Advance and Charge rolls made for this unit.\n- Goaded to Slaughter: While this unit is within Synapse Range of your army, each time a model in this unit makes a melee attack, add 1 to the Hit roll.",
        "source": "Wahapedia CSV / Synaptic Nexus",
        "priority": 5
      }
    ],
